+import Yoga, {type Node as YogaNode} from 'yoga-layout';
+import {type DOMElement} from './dom.js';
+
+type Track =
+	| {kind: 'fixed'; size: number}
+	| {kind: 'fr'; size: number}
+	| {kind: 'auto'}
+	| {kind: 'minmax'; min: number; max: number | 'fr'};
+
+type Placement = {column: number; columnEnd: number; row: number; rowEnd: number};
+
+const parseTracks = (template: string | undefined): Track[] => {
+	if (!template) return [{kind: 'auto'}];
+
+	const tokens = template.match(/minmax\\([^)]*\\)|\\S+/g) ?? [];
+	return tokens.map(token => {
+		if (token === 'auto') return {kind: 'auto'};
+		const minmax = /^minmax\\((\\d+(?:\\.\\d+)?),\\s*(\\d+(?:\\.\\d+)?|\\d+(?:\\.\\d+)?fr)\\)$/.exec(token);
+		if (minmax) {
+			const max = minmax[2]!;
+			return {kind: 'minmax', min: Number(minmax[1]), max: max.endsWith('fr') ? 'fr' : Number(max)};
+		}
+
+		if (/^\\d+(?:\\.\\d+)?fr$/.test(token)) return {kind: 'fr', size: Number.parseFloat(token)};
+		if (/^\\d+(?:\\.\\d+)?$/.test(token)) return {kind: 'fixed', size: Number(token)};
+		throw new Error(`Invalid grid track size: ${token}`);
+	});
+};
+
+const parsePlacement = (value: number | string | undefined): [number, number] | undefined => {
+	if (typeof value === 'number') return [value, value + 1];
+	if (!value) return;
+	const match = /^(\\d+)\\s*\\/\\s*(\\d+)$/.exec(value);
+	if (!match) throw new Error(`Invalid grid placement: ${value}`);
+	return [Number(match[1]), Number(match[2])];
+};
+
+const sizesForTracks = (tracks: Track[], available: number, gap: number, items: Array<{placement: Placement; size: number}>, axis: 'column' | 'row'): number[] => {
+	const sizes = tracks.map(track => track.kind === 'fixed' ? track.size : track.kind === 'minmax' ? track.min : 0);
+	for (const {placement, size} of items) {
+		const start = axis === 'column' ? placement.column - 1 : placement.row - 1;
+		const end = axis === 'column' ? placement.columnEnd - 1 : placement.rowEnd - 1;
+		if (end - start !== 1 || !tracks[start]) continue;
+		const track = tracks[start]!;
+		if (track.kind === 'auto') sizes[start] = Math.max(sizes[start]!, size);
+		if (track.kind === 'minmax' && typeof track.max === 'number') sizes[start] = Math.max(sizes[start]!, Math.min(size, track.max));
+	}
+
+	const remaining = Math.max(0, available - gap * Math.max(0, tracks.length - 1) - sizes.reduce((sum, size) => sum + size, 0));
+	const frTotal = tracks.reduce((sum, track) => sum + (track.kind === 'fr' ? track.size : track.kind === 'minmax' && track.max === 'fr' ? 1 : 0), 0);
+	if (frTotal > 0) {
+		tracks.forEach((track, index) => {
+			if (track.kind === 'fr') sizes[index] = remaining * track.size / frTotal;
+			if (track.kind === 'minmax' && track.max === 'fr') sizes[index] = sizes[index]! + remaining / frTotal;
+		});
+	}
+
+	return sizes;
+};
+
+const layoutGrid = (node: DOMElement): void => {
+	for (const child of node.childNodes) {
+		if (child.nodeName !== '#text') layoutGrid(child as DOMElement);
+	}
+	if (node.style.display !== 'grid' || !node.yogaNode) return;
+
+	const columns = parseTracks(node.style.gridTemplateColumns);
+	const declaredRows = node.style.gridTemplateRows ? parseTracks(node.style.gridTemplateRows) : [];
+	const children = node.childNodes.filter((child): child is DOMElement => child.nodeName !== '#text' && Boolean(child.yogaNode));
+	const placements: Placement[] = [];
+	let cursor = 0;
+	for (const child of children) {
+		const columnPlacement = parsePlacement(child.style.gridColumn);
+		const rowPlacement = parsePlacement(child.style.gridRow);
+		const column = columnPlacement?.[0] ?? cursor % columns.length + 1;
+		const columnEnd = columnPlacement?.[1] ?? column + 1;
+		const row = rowPlacement?.[0] ?? Math.floor(cursor / columns.length) + 1;
+		const rowEnd = rowPlacement?.[1] ?? row + 1;
+		placements.push({column, columnEnd, row, rowEnd});
+		cursor++;
+	}
+
+	const rowCount = Math.max(declaredRows.length, ...placements.map(placement => placement.rowEnd - 1), 1);
+	const rows = [...declaredRows];
+	while (rows.length < rowCount) rows.push({kind: 'auto'});
+	const yogaNode = node.yogaNode;
+	const columnGap = node.style.columnGap ?? node.style.gap ?? 0;
+	const rowGap = node.style.rowGap ?? node.style.gap ?? 0;
+	const left = yogaNode.getComputedPadding(Yoga.EDGE_LEFT) + yogaNode.getComputedBorder(Yoga.EDGE_LEFT);
+	const top = yogaNode.getComputedPadding(Yoga.EDGE_TOP) + yogaNode.getComputedBorder(Yoga.EDGE_TOP);
+	const availableWidth = yogaNode.getComputedWidth() - left - yogaNode.getComputedPadding(Yoga.EDGE_RIGHT) - yogaNode.getComputedBorder(Yoga.EDGE_RIGHT);
+	const availableHeight = yogaNode.getComputedHeight() - top - yogaNode.getComputedPadding(Yoga.EDGE_BOTTOM) - yogaNode.getComputedBorder(Yoga.EDGE_BOTTOM);
+	const itemSizes = children.map((child, index) => ({placement: placements[index]!, width: child.yogaNode!.getComputedWidth(), height: child.yogaNode!.getComputedHeight()}));
+	const columnSizes = sizesForTracks(columns, availableWidth, columnGap, itemSizes.map(item => ({placement: item.placement, size: item.width})), 'column');
+	const rowSizes = sizesForTracks(rows, availableHeight, rowGap, itemSizes.map(item => ({placement: item.placement, size: item.height})), 'row');
+	const offsets = (sizes: number[], gap: number, initial: number) => sizes.reduce<number[]>((result, size) => [...result, (result.at(-1) ?? initial - gap) + size + gap], []).map((offset, index) => index === 0 ? initial : offset - sizes[index]!);
+	const columnOffsets = offsets(columnSizes, columnGap, left);
+	const rowOffsets = offsets(rowSizes, rowGap, top);
+
+	children.forEach((child, index) => {
+		const placement = placements[index]!;
+		const width = columnSizes.slice(placement.column - 1, placement.columnEnd - 1).reduce((sum, size) => sum + size, 0) + columnGap * (placement.columnEnd - placement.column - 1);
+		const height = rowSizes.slice(placement.row - 1, placement.rowEnd - 1).reduce((sum, size) => sum + size, 0) + rowGap * (placement.rowEnd - placement.row - 1);
+		child.yogaNode!.setPositionType(Yoga.POSITION_TYPE_ABSOLUTE);
+		child.yogaNode!.setPosition(Yoga.EDGE_LEFT, columnOffsets[placement.column - 1]!);
+		child.yogaNode!.setPosition(Yoga.EDGE_TOP, rowOffsets[placement.row - 1]!);
+		child.yogaNode!.setWidth(width);
+		child.yogaNode!.setHeight(height);
+	});
+
+	if (node.style.height === undefined) yogaNode.setHeight(top + rowSizes.reduce((sum, size) => sum + size, 0) + rowGap * Math.max(0, rowSizes.length - 1) + yogaNode.getComputedPadding(Yoga.EDGE_BOTTOM) + yogaNode.getComputedBorder(Yoga.EDGE_BOTTOM));
+};
+
+export const applyGridLayout = (rootNode: DOMElement): void => {
+	layoutGrid(rootNode);
+};
